const state = $getWorkflowStaticData('global');
// Reset all state at the start of each run
state.jobs           = [];
state.currentCompany = '';
state.currentSector  = '';
state.currentUrl     = '';

const activeItems = $input.all().filter(item => {
  const val = String(item.json.Active || '').trim().toUpperCase();
  return val === 'TRUE' || val === '1' || val === 'YES';
});

if (activeItems.length === 0) {
  throw new Error('No active companies found. Check the Active column in your Google Sheet.');
}

return activeItems;

const item  = $input.first().json;
const state = $getWorkflowStaticData('global');
state.currentCompany = item.Company       || '';
state.currentSector  = item.Sector        || '';
state.currentUrl     = item['Career URL'] || '';
return $input.all();

const state   = $getWorkflowStaticData('global');
const company = state.currentCompany || '';
const sector  = state.currentSector  || '';
const url     = state.currentUrl     || '';

const item = $input.first();
let markdown = '';

try {
  if (item.json?.data?.markdown) {
    markdown = item.json.data.markdown.substring(0, 12000);
  }
} catch (e) { markdown = ''; }

if (!markdown) {
  markdown = `Career page for ${company}. No readable content retrieved from: ${url}`;
}

return [{ json: { company, sector, url, markdown } }];

const state   = $getWorkflowStaticData('global');
const company = state.currentCompany || '';
const sector  = state.currentSector  || '';
const url     = state.currentUrl     || '';
const existingJobs = Array.isArray(state.jobs) ? state.jobs : [];

const nigeriaKeywords   = ['nigeria', 'lagos', 'abuja', 'port harcourt', 'kano', 'ibadan', 'ogun', 'benin city'];
const nigeriaUrlPatterns = ['.ng/', '/nigeria', '/ng/', 'country=ng', 'country=NG', '/NGA', 'locationsearch=nigeria', 'location=nigeria', 'l=nigeria'];
const isNigeriaSourceUrl = nigeriaUrlPatterns.some(p => url.toLowerCase().includes(p.toLowerCase()));

let newJobs = [];

try {
  const response = $input.first().json;

  if (!response?.choices?.[0]?.message?.content) {
    throw new Error('No valid Groq response for: ' + company);
  }

  const parsed = JSON.parse(response.choices[0].message.content);
  const jobs   = Array.isArray(parsed.jobs) ? parsed.jobs : [];

  for (const job of jobs) {
    const location = (job.location || '').toLowerCase();
    const isNigeriaJob =
      isNigeriaSourceUrl ||
      nigeriaKeywords.some(kw => location.includes(kw)) ||
      location === '' ||
      location === 'n/a';

    if (isNigeriaJob) {
      newJobs.push({
        company,
        sector,
        title:      job.title      || 'Unknown Role',
        location:   job.location   || 'Nigeria',
        jobUrl:     job.url        || url,
        department: job.department || ''
      });
    }
  }
} catch (e) {
  newJobs = [];
}

// Direct mutation — no set() call, no internal logger, no sandbox crash
state.jobs = [...existingJobs, ...newJobs];

return [{ json: { processed: true, company, jobsFound: newJobs.length } }];

const state   = $getWorkflowStaticData('global');
const allJobs = Array.isArray(state.jobs) ? state.jobs : [];
return [{ json: { allJobs, totalCount: allJobs.length } }];

const { allJobs } = $input.first().json;
const date = new Date().toLocaleDateString('en-GB', {
  day: 'numeric', month: 'long', year: 'numeric'
});

// Group by sector → company
const bySector = {};
for (const job of allJobs) {
  const s = job.sector || 'Other';
  const c = job.company;
  if (!bySector[s]) bySector[s] = {};
  if (!bySector[s][c]) bySector[s][c] = [];
  bySector[s][c].push(job);
}

const sectorCount  = Object.keys(bySector).length;
const companyCount = Object.values(bySector).reduce((a, s) => a + Object.keys(s).length, 0);

const sectorColors = {
  'Consumer Goods': '#27ae60',
  'Consulting':     '#8e44ad',
  'Oil & Gas':      '#e67e22',
  'Banking':        '#2980b9',
  'Telecom':        '#16a085',
  'Fintech':        '#c0392b',
  'Tech':           '#2c3e50'
};

let html = `
<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto;color:#2c3e50;">
  <h2 style="background:#2c3e50;color:white;padding:16px;margin:0;border-radius:6px 6px 0 0;">
    &#127475;&#127468; Nigerian Job Openings &mdash; ${date}
  </h2>
  <div style="background:#ecf0f1;padding:12px 16px;border-radius:0 0 6px 6px;margin-bottom:20px;">
    <strong>${allJobs.length} opening${allJobs.length !== 1 ? 's' : ''}</strong>
    across ${companyCount} compan${companyCount !== 1 ? 'ies' : 'y'}
    in ${sectorCount} sector${sectorCount !== 1 ? 's' : ''}
  </div>`;

for (const [sector, companies] of Object.entries(bySector)) {
  const color = sectorColors[sector] || '#7f8c8d';
  html += `<h3 style="color:${color};border-left:4px solid ${color};padding-left:10px;margin-top:24px;">${sector}</h3>`;
  for (const [company, jobs] of Object.entries(companies)) {
    html += `<div style="margin-left:14px;margin-bottom:12px;">
      <strong style="font-size:15px;">${company}</strong>
      <ul style="margin:4px 0;">`;
    for (const job of jobs) {
      const link = job.jobUrl
        ? `<a href="${job.jobUrl}" style="color:#2980b9;text-decoration:none;">${job.title}</a>`
        : job.title;
      const dept = job.department
        ? ` &bull; <em style="color:#7f8c8d;">${job.department}</em>`
        : '';
      html += `<li style="margin:4px 0;">${link} &mdash; <span style="color:#7f8c8d;">${job.location}</span>${dept}</li>`;
    }
    html += `</ul></div>`;
  }
}

html += `
  <hr style="border:none;border-top:1px solid #eee;margin-top:30px;">
  <p style="color:#bdc3c7;font-size:12px;text-align:center;">
    Generated by your n8n Job Scanner &bull; Powered by Firecrawl + Groq &bull; Good luck!
  </p>
</div>`;

const subject = `[Job Scanner] ${allJobs.length} Nigerian Opening${allJobs.length !== 1 ? 's' : ''} — ${date}`;

return [{ json: { subject, htmlBody: html } }];
